// Parse telemetry and enrich with digital twin metadata
msg.payload.timestamp = new Date().toISOString();
msg.payload.gateway_processed = true;

// Extract room ID from topic
var topicParts = msg.topic.split('/');
var building = topicParts[1];
var floor = topicParts[2];
var room = topicParts[3];

msg.room_id = building + '-f' + floor.replace('f', '').padStart(2, '0') + '-r' + room.replace('r', '').padStart(3, '0');
msg.building = building;
msg.floor = floor;
msg.room = room;

return msg;

// Store telemetry for floor-level aggregation
var context = this.context;
var floorKey = msg.building + '-' + msg.floor;

// Initialize floor data if not exists
if (!context.get(floorKey)) {
    context.set(floorKey, {
        temperatures: [],
        humidity: [],
        occupancy: 0,
        roomCount: 0
    });
}

var floorData = context.get(floorKey);

// Add current reading
if (msg.payload.sensors.temperature) {
    floorData.temperatures.push(msg.payload.sensors.temperature);
}
if (msg.payload.sensors.humidity) {
    floorData.humidity.push(msg.payload.sensors.humidity);
}
if (msg.payload.sensors.occupancy) {
    floorData.occupancy++;
}
floorData.roomCount++;

// Calculate aggregates
var aggregates = {
    floor_id: floorKey,
    avg_temperature: floorData.temperatures.reduce((a, b) => a + b, 0) / floorData.temperatures.length,
    avg_humidity: floorData.humidity.reduce((a, b) => a + b, 0) / floorData.humidity.length,
    occupancy_rate: (floorData.occupancy / floorData.roomCount) * 100,
    timestamp: new Date().toISOString()
};

msg.payload = aggregates;
msg.topic = 'floor/aggregates/' + floorKey;

return msg;

// Process incoming commands from ThingsBoard dashboard
// Add command ID for idempotency
msg.payload.command_id = Date.now().toString(36) + Math.random().toString(36).substr(2);
msg.payload.timestamp = new Date().toISOString();

// Log command for audit
msg.payload.gateway_audit = {
    processed_by: 'nodered-gateway',
    timestamp: new Date().toISOString()
};

return msg;

// Verify SHA-256 hash of OTA update
var crypto = require('crypto');

// Create hash of payload (excluding the hash field itself)
var payloadCopy = JSON.parse(JSON.stringify(msg.payload));
var providedHash = payloadCopy.hash;
delete payloadCopy.hash;

// Calculate hash
var payloadString = JSON.stringify(payloadCopy, Object.keys(payloadCopy).sort());
var calculatedHash = crypto.createHash('sha256').update(payloadString).digest('hex');

msg.ota_verification = {
    provided_hash: providedHash,
    calculated_hash: calculatedHash,
    valid: calculatedHash === providedHash,
    timestamp: new Date().toISOString()
};

if (!msg.ota_verification.valid) {
    msg.payload.security_alert = {
        type: 'TAMPERING_DETECTED',
        update_id: msg.payload.update_id,
        details: msg.ota_verification
    };
    // Send to ThingsBoard security alert topic
    msg.topic = 'security/alerts';
} else {
    msg.topic = 'ota/verified';
}

return msg;

// Compare desired vs reported states
var desired = msg.payload.desired || {};
var reported = msg.payload.reported || {};

var mismatches = [];

// Check HVAC mode
if (desired.hvac_mode && desired.hvac_mode !== reported.hvac_mode) {
    mismatches.push({
        attribute: 'hvac_mode',
        desired: desired.hvac_mode,
        reported: reported.hvac_mode
    });
}

// Check lighting dimmer
if (desired.lighting_dimmer !== undefined && desired.lighting_dimmer !== reported.lighting_dimmer) {
    mismatches.push({
        attribute: 'lighting_dimmer',
        desired: desired.lighting_dimmer,
        reported: reported.lighting_dimmer
    });
}

// Check target temperature
if (desired.target_temp !== undefined && Math.abs(desired.target_temp - (reported.target_temp || 0)) > 0.5) {
    mismatches.push({
        attribute: 'target_temp',
        desired: desired.target_temp,
        reported: reported.target_temp
    });
}

msg.shadow_status = {
    room_id: msg.room_id,
    sync_status: mismatches.length === 0 ? 'synced' : (mismatches.length >= 3 ? 'conflict' : 'out_of_sync'),
    mismatches: mismatches,
    timestamp: new Date().toISOString()
};

return msg;

// Return shadow sync status for dashboard
// In production, this would query a database
msg.payload = {
    total_devices: 200,
    synced: 185,
    out_of_sync: 12,
    conflicts: 3,
    offline: 5,
    sync_rate: 92.5,
    timestamp: new Date().toISOString()
};

msg.headers = {
    'Content-Type': 'application/json'
};

return msg;
